/** 프로필 id → 원본 nav 마크업(브랜드=로고, 링크=대시보드 섹션, 다크토글 유지). */
export const DS_NAV: Record<string, string> = {"apple": "<style>[data-theme=\"dark\"] .nav-brand img{filter:invert(1) brightness(1.8)}</style><nav class=\"nav\"> <span class=\"nav-brand\"><img src=\"{{BCAVE_CI}}\" alt=\"B.CAVE\" style=\"height:20px;vertical-align:middle;display:inline-block\"></span> <ul class=\"nav-links\"><li><a href=\"#overview\">개요</a></li><li><a href=\"#charts\">분포</a></li><li><a href=\"#table\">목록</a></li></ul> <button class=\"switch\" id=\"themeToggle\" role=\"switch\" aria-checked=\"false\" aria-label=\"다크 모드 전환\"></button> </nav>"};

/** 프로필 id → 원본 토글/인터랙션 JS. */
export const DS_JS: Record<string, string> = {"apple": "// 다크 모드 토글\nconst toggle = document.getElementById(\"themeToggle\");\ntoggle.addEventListener(\"click\", () => {\n  const isDark = document.documentElement.dataset.theme === \"dark\";\n  document.documentElement.dataset.theme = isDark ? \"\" : \"dark\";\n  toggle.setAttribute(\"aria-checked\", String(!isDark));\n});\n\n// 시스템 다크 모드 감지\nif (window.matchMedia(\"(prefers-color-scheme: dark)\").matches) {\n  document.documentElement.dataset.theme = \"dark\";\n  toggle.setAttribute(\"aria-checked\", \"true\");\n}\n\n// 데모 스위치 / 세그먼트 인터랙션\ndocument.querySelectorAll(\".demo-switch\").forEach(sw => {\n  sw.addEventListener(\"click\", () => {\n    sw.setAttribute(\"aria-checked\", String(sw.getAttribute(\"aria-checked\") !== \"true\"));\n  });\n});\ndocument.querySelectorAll(\".segmented\").forEach(group => {\n  group.querySelectorAll(\"button\").forEach(btn => {\n    btn.addEventListener(\"click\", () => {\n      group.querySelectorAll(\"button\").forEach(b => b.setAttribute(\"aria-pressed\", \"false\"));\n      btn.setAttribute(\"aria-pressed\", \"true\");\n    });\n  });\n});"};
